checks.run:
kubectl --context kind-kubeadv-core create namespace m5-dd-check --dry-run=client -o yaml | kubectl --context kind-kubeadv-core apply -f - >/dev/null; printf 'apiVersion: kubeadv.io/v1alpha1
kind: Website
metadata: {name: prunechk, namespace: m5-dd-check}
spec: {host: p.io, replicas: 1, bogusField: drop-me}
' | kubectl --context kind-kubeadv-core apply --validate=false -f - >/dev/null; kubectl --context kind-kubeadv-core -n m5-dd-check get website prunechk -o jsonpath='{.spec}'; echo; kubectl --context kind-kubeadv-core delete namespace m5-dd-check --wait=false >/dev/null 2>&1
